pages['HB9 Exchange']=function(){const b=data.wallets,market=data.settings.market||{buyPrice:hb9PriceValue(),sellPrice:hb9PriceValue(),spreadPercent:0};page.innerHTML=`<section class="exchange-page"><section class="card exchange-chart"><div class="income-header"><div><h2>HB9 Exchange</h2><p class="muted">Admin controlled HB9/USDT launch market</p></div><b class="exchange-price">${money(market.buyPrice)}</b></div><div class="exchange-market"><div><small>Buy Price</small><b>${money(market.buyPrice)}</b></div><div><small>Sell Price</small><b>${money(market.sellPrice)}</b></div><div><small>Spread</small><b>${Number(market.spreadPercent||0).toFixed(2)}%</b></div><div><small>Pair</small><b>HB9/USDT</b></div></div></section><section class="card exchange-wallets"><div><small>USDT Wallet</small><b>${money(b.usdt)}</b></div><div><small>HB9 Wallet</small><b>${points(b.hb9)} HB9</b></div></section><section class="card exchange-convert"><div class="tabs"><button class="active" data-exchange-tab="buy">Buy HB9</button><button data-exchange-tab="sell">Sell HB9</button></div><form id="exchange-form"><div class="exchange-panel buy"><div class="field"><label>USDT Amount</label><input name="amount" type="number" min="0.01" max="${b.usdt}" step="0.01"></div><div class="field"><label>HB9 You Receive</label><input class="exchange-output" readonly value="0 HB9"></div><button class="primary">Convert To HB9</button></div><div class="exchange-panel sell" hidden><div class="field"><label>HB9 Amount</label><input name="sellAmount" type="number" min="0.01" max="${b.hb9}" step="0.01"></div><div class="field"><label>USDT You Receive</label><input class="exchange-output" readonly value="$0.00"></div><button class="primary">Convert To USDT</button></div></form></section><p class="exchange-note">Deposits credit USDT only. Buy HB9 here to stake; sell HB9 here before withdrawing USDT BEP20.</p></section>`;const form=page.querySelector('#exchange-form'),buy=form.querySelector('.buy'),sell=form.querySelector('.sell'),buyAmount=buy.querySelector('[name="amount"]'),sellAmount=sell.querySelector('[name="sellAmount"]');page.querySelectorAll('[data-exchange-tab]').forEach(tab=>tab.onclick=()=>{const isBuy=tab.dataset.exchangeTab==='buy';page.querySelectorAll('[data-exchange-tab]').forEach(item=>item.classList.toggle('active',item===tab));buy.hidden=!isBuy;sell.hidden=isBuy});buyAmount.oninput=()=>buy.querySelector('.exchange-output').value=`${points(Number(buyAmount.value||0)/market.buyPrice)} HB9`;sellAmount.oninput=()=>sell.querySelector('.exchange-output').value=money(Number(sellAmount.value||0)*market.sellPrice);buy.onsubmit=async event=>{event.preventDefault();const done=loading(event.submitter,'Converting...');try{toast((await api('/api/convert',{method:'POST',body:JSON.stringify({amount:buyAmount.value})})).message);load()}catch(error){toast(error.message,'error')}finally{done()}};sell.onsubmit=async event=>{event.preventDefault();const done=loading(event.submitter,'Converting...');try{toast((await api('/api/exchange/sell',{method:'POST',body:JSON.stringify({amount:sellAmount.value})})).message);load()}catch(error){toast(error.message,'error')}finally{done()}}};
