pages.Salary=function(){const s=data.salary||{},current=s.currentRank,next=s.nextRank,cap=s.salaryCap||{},rankRows=(s.rankProgress||[]).map(x=>`<tr><td>${esc(x.rankName)}</td><td>${x.directCount} / ${x.requiredDirectReferrals}</td><td>${money(x.selfPackageUsd)} / ${money(x.requiredSelfPackageUsd)}</td><td>${money(x.teamBusinessUsd)} / ${money(x.requiredTeamBusinessUsd)}</td><td>${money(x.salaryUsd)}</td><td>${badge(x.qualified?'Qualified':'Pending',x.qualified?'yes':'unpaid')}</td></tr>`).join(''),payoutRows=(s.payoutHistory||[]).slice().reverse().map(x=>`<tr><td>${x.cycleStart} to ${x.cycleEnd}</td><td>${esc(x.rankName||`Rank ${x.rank}`)}</td><td>${money(x.usdAmount)}</td><td>${points(x.hb9Amount)} HB9</td><td>${badge(x.status,x.status==='credited'?'paid':x.status==='capped'?'flush':'unpaid')}</td></tr>`).join('');page.innerHTML=`<div class="grid stats">${stat('Current Rank',current?esc(current.rankName):'Not qualified')}${stat('Next Rank',next?esc(next.rankName):'Top rank reached')}${stat('Salary Cap Used',money(cap.usedUsd||0))}${stat('Salary Cap Remaining',money(cap.remainingUsd||0))}</div><section class="card income"><div class="income-header"><div><h2>Salary Progress</h2><p class="muted">Qualification uses direct staking minimums, self package, and 20-level active team business.</p></div>${badge(current?'Qualified':'Pending',current?'yes':'unpaid')}</div>${table(['Rank','Directs','Self Package','20-Level Team','15-Day Salary','Status'],rankRows,'No salary ranks','Salary rank rules will appear here.')}</section><section class="card income"><h2>Salary Cap</h2><div class="incomegrid"><div class="incomeitem"><label>Personal Investment</label><strong>${money(cap.personalInvestmentUsd||0)}</strong></div><div class="incomeitem"><label>Maximum Cap</label><strong>${money(cap.maxSalaryCapUsd||0)}</strong></div><div class="incomeitem"><label>Total Paid</label><strong>${money(cap.totalSalaryPaidUsd||0)}</strong></div><div class="incomeitem"><label>Remaining</label><strong>${money(cap.remainingUsd||0)}</strong></div></div></section><section class="card income"><h2>Salary Payout History</h2>${table(['Cycle','Rank','USD','HB9','Status'],payoutRows,'No salary payouts yet','Salary income is paid every 15 days when qualified and within cap.')}</section>`};
const salaryAdminRender=renderAdmin;renderAdmin=function(adminData){salaryAdminRender(adminData);const tabs=document.querySelector('.tabs');if(tabs&&!tabs.querySelector('[data-tab="Salary Report"]'))tabs.insertAdjacentHTML('beforeend',`<button class="${adminTab==='Salary Report'?'active':''}" data-tab="Salary Report">Salary Report</button>`);tabs?.querySelector('[data-tab="Salary Report"]')?.addEventListener('click',()=>{adminTab='Salary Report';renderAdmin(adminData)});if(adminTab!=='Salary Report')return;const name=id=>esc(adminData.users.find(user=>user.id===id)?.name||id),rows=(adminData.salaryPayouts||[]).slice().reverse().map(x=>`<tr><td>${x.cycleStart}</td><td>${name(x.userId)}</td><td>${esc(x.rankName||`Rank ${x.rank}`)}</td><td>${money(x.usdAmount)}</td><td>${points(x.hb9Amount)} HB9</td><td>${badge(x.status,x.status==='credited'?'paid':x.status==='capped'?'flush':'unpaid')}</td><td>${esc(x.reason||'')}</td></tr>`).join(''),qualRows=(adminData.users||[]).map(x=>{const salary=x.summary.salary||{},rank=salary.currentRank;return `<tr><td>${esc(x.name)}</td><td>${rank?esc(rank.rankName):'Not qualified'}</td><td>${salary.directCountProgress?`${salary.directCountProgress.current} / ${salary.directCountProgress.required}`:'-'}</td><td>${salary.selfPackageProgress?`${money(salary.selfPackageProgress.current)} / ${money(salary.selfPackageProgress.required)}`:'-'}</td><td>${salary.teamBusinessProgress?`${money(salary.teamBusinessProgress.current)} / ${money(salary.teamBusinessProgress.required)}`:'-'}</td><td>${money(salary.salaryCap?.remainingUsd||0)}</td></tr>`}).join('');document.querySelector('.report-stack').innerHTML=`<section class="card income"><div class="income-header"><div><h2>Salary Income Plan</h2><p class="muted">Runs one salary payout per user per 15-day cycle.</p></div><button class="primary" id="run-salary">Run Salary Payout</button></div></section><section class="card">${table(['User','Current Rank','Directs','Self Package','20-Level Team','Cap Remaining'],qualRows,'No salary qualifications')}</section><section class="card">${table(['Cycle Start','User','Rank','USD','HB9','Status','Reason'],rows,'No salary payouts yet')}</section>`;document.querySelector('#run-salary')?.addEventListener('click',async e=>{if(!await confirmAction('Run Salary Payout','Create salary payouts for qualified users in the current 15-day cycle.','Run Salary'))return;const done=loading(e.currentTarget,'Processing...');try{const x=await api('/api/admin/salary/run',{method:'POST'}),s=x.summary;toast(`${x.message}: ${s.creditedUsers} credited, ${s.queuedUsers} queued, ${s.cappedUsers} capped`);pages.Admin()}catch(error){toast(error.message,'error')}finally{done()}})};
pages.Team=async function(){
  const renderTeamLevels=report=>{
    const summary=report?.summary||{totalLevels:20,totalMembers:0,activeMembers:0,totalInvestmentUsd:0,totalHb9Equivalent:0};
    const levels=report?.levels||Array.from({length:20},(_,i)=>({level:i+1,memberCount:0,totalInvestmentUsd:0,totalStakeHb9Equivalent:0,members:[]}));
    const field=(label,value)=>`<span><small>${label}</small>${value}</span>`;
    const memberRow=member=>`<div class="level-team-member"><div class="member-main"><b>${esc(member.name||'-')}</b><span>${esc(member.email||'-')}</span></div>${field('Status',badge(member.active?'Active':'Inactive',member.active?'yes':'no'))}${field('Join Date',esc(String(member.joinedAt||'').slice(0,10)||'-'))}${field('Stake Asset',esc(member.stakeAsset||'-'))}${field('Stake Amount',`${points(member.totalStakeAmount||0)} ${esc(member.stakeAsset||'')}`)}${field('Investment (USD)',money(member.activeStake||0))}${field('Total Investment',money(member.totalInvestmentUsd||0))}${field('HB9 Equivalent',`${points(member.hb9EquivalentAmount||0)} HB9`)}${field("Today's Income",`${points(member.todayIncome||0)} HB9`)}${field('Total Income',`${points(member.totalIncome||0)} HB9`)}${field('Last Stake Date',esc(member.lastStakeDate||'-'))}</div>`;
    const levelCard=level=>`<details class="team-level-card" ${level.memberCount?'':'data-empty="true"'}><summary><strong>Level ${level.level}</strong><span>${level.memberCount} Members</span><span>${money(level.totalInvestmentUsd)} Investment</span><span>${points(level.totalStakeHb9Equivalent)} HB9</span></summary><div class="team-level-members">${level.members.length?level.members.map(memberRow).join(''):'<div class="team-level-empty">No members on this level</div>'}</div></details>`;
    page.innerHTML=`<section class="team-clean-page team-level-page"><section class="card team-summary"><h2>Level Team</h2><div><span>Total Team</span><b>${summary.totalMembers}</b></div><div><span>Active Team</span><b>${summary.activeMembers||0}</b></div><div><span>Total Investment</span><b>${money(summary.totalInvestmentUsd||0)}</b></div><div><span>HB9 Equivalent</span><b>${points(summary.totalHb9Equivalent||0)} HB9</b></div></section><section class="team-level-list">${levels.map(levelCard).join('')}</section></section>`;
  };
  page.innerHTML='<section class="card team-empty"><b>Loading 20-level team...</b></section>';
  try{const report=await api('/api/team/levels');if(view==='Team')renderTeamLevels(report)}catch(error){page.innerHTML=`<section class="card team-empty"><b>${esc(error.message||'Unable to load team')}</b></section>`}
};const salaryDashboardIncomePage=pages.Dashboard;
