pages.Deposit=async function(){
  const label=item=>item.status==='credited'?'Credited':item.status==='failed'?'Failed':item.status==='confirming'?'Confirming':item.status==='pending'?'Waiting for payment':item.status||'Pending';
  const row=item=>`<tr><td>${String(item.createdAt||'').slice(0,10)}</td><td>${money(item.amount)}</td><td>${esc(item.provider||'NOWPayments')}</td><td>${esc(item.paymentId||item.invoiceId||'-')}</td><td>${badge(label(item),item.status==='credited'?'paid':item.status==='failed'?'no':'unpaid')}</td></tr>`;
  const rows=(data.deposits||[]).slice().reverse().map(row).join(''),service=data.depositService||{},history=`<div class="tablewrap"><table class="table"><thead><tr><th>Date</th><th>Amount</th><th>Provider</th><th>Payment</th><th>Status</th></tr></thead><tbody>${rows}</tbody></table></div>`;
  page.innerHTML=`<section class="card"><div class="income-header"><div><h2>Deposit USDT</h2><p class="muted">Enter a USDT amount and complete payment on NOWPayments.</p></div>${badge('NOWPayments',service.configured?'paid':'unpaid')}</div><form id="deposit-intent" class="formrow"><div class="field"><label>USDT amount</label><input name="amount" type="number" min="0.01" step="0.01" placeholder="0.00" ${service.configured?'':'disabled'}></div><button class="primary" ${service.configured?'':'disabled'}>Deposit</button></form><div id="deposit-payment-panel" class="deposit-address-box" style="display:${service.configured?'none':'flex'};align-items:center;gap:10px;padding:13px;border:1px solid var(--line);border-radius:13px;background:rgba(5,8,17,.32)">${service.configured?'':`<b>${esc(service.message||'NOWPayments deposit gateway is not configured yet.')}</b>`}</div></section><section class="card income"><div class="income-header"><div><h2>Deposit History</h2><p class="muted">Pending, confirming, credited, and failed NOWPayments deposits.</p></div></div>${history}</section>`;
  const form=page.querySelector('#deposit-intent'),panel=page.querySelector('#deposit-payment-panel');
  if(!service.configured||!form)return;
  form.onsubmit=async event=>{event.preventDefault();const done=loading(event.submitter,'Creating...');try{const result=await api('/api/deposits',{method:'POST',body:JSON.stringify({amount:form.elements.amount.value})}),deposit=result.deposit,link=deposit.invoiceUrl||result.payment?.invoice_url||result.payment?.payment_url,payAddress=deposit.payAddress||result.payment?.pay_address,payCurrency=deposit.payCurrency||result.payment?.pay_currency;panel.style.display='flex';panel.innerHTML=`<div style="min-width:0;flex:1"><b>${esc(label(deposit))}</b>${link?`<p class="muted" style="margin:4px 0 0;overflow-wrap:anywhere">${esc(link)}</p>`:''}${payAddress?`<p class="muted" style="margin:4px 0 0;overflow-wrap:anywhere">${esc(payCurrency||'')} ${esc(payAddress)}</p>`:''}</div>${link?`<a class="ghost" style="flex:0 0 auto;text-decoration:none" href="${esc(link)}" target="_blank" rel="noopener">Pay</a>`:''}`;data.deposits=[...(data.deposits||[]),deposit];const tbody=page.querySelector('section.card.income tbody');if(tbody)tbody.insertAdjacentHTML('afterbegin',row(deposit));toast(result.message||'NOWPayments deposit created')}catch(error){toast(error.message,'error')}finally{done()}};
};
