async function boot(){applyPresentation();const authMode=new URLSearchParams(location.search).get('auth')||new URLSearchParams(location.hash.replace(/^#\??/,'')).get('auth');const urlReferral=referralParam();if(urlReferral)storeReferralCode(urlReferral);if(authMode==='login'||authMode==='register'||urlReferral){localStorage.removeItem('hb9token');localStorage.removeItem('hb9user');token=null;me=null;auth(urlReferral?'register':authMode);return}if(token)load();else auth()}
boot();
